#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long m = (N + 1) / 2; // number of odd side lengths
        long long a = N + 2;
        long long term1 = (2LL * m * (m + 1) * (2 * m + 1)) / 3; // (2/3)*m*(m+1)*(2m+1)
        long long term2 = 2LL * a * m * (m + 1);
        long long term3 = m * a * a;
        long long ans = term1 - term2 + term3;
        printf("%lld\n", ans);
    }
    return 0;
}

