const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for(let t = 0; t < T; t++){
  const N = Number(input[idx++]);
  const m = Math.floor((N + 1) / 2);
  const a = N + 2;
  const term1 = (2 * m * (m + 1) * (2 * m + 1)) / 3; // (2/3)*m*(m+1)*(2m+1)
  const term2 = 2 * a * m * (m + 1);
  const term3 = m * a * a;
  const ans = term1 - term2 + term3;
  results.push(String(Math.trunc(ans)));
}
